#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

uint32_t expand(uint32_t key) {
    return key ^ (key << 16) ^ (key * 12345);
}

uint8_t g_function(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

uint32_t f_function(uint32_t input_val) {
    uint8_t x[4], y[4];
    uint32_t val = input_val;
    for (int i = 0; i < 4; i++) {
        x[i] = val & 0xFF;
        val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    uint32_t output = 0;
    for (int i = 0; i < 4; i++) {
        output |= (uint32_t)y[i] << (8 * i);
    }
    return output;
}

uint32_t getleft(uint64_t x) { return (x >> 32) & 0xFFFFFFFF; }
uint32_t getright(uint64_t x) { return x & 0xFFFFFFFF; }
uint64_t merge(uint32_t left, uint32_t right) {
    return ((uint64_t)left << 32) | right;
}

uint64_t encrypt(uint64_t plaintext, uint32_t *keys) {
    uint32_t left = getleft(plaintext);
    uint32_t right = getright(plaintext);
    right ^= left;
    for (int r = 0; r < 4; r++) {
        uint32_t mixed = f_function(right ^ keys[r]);
        uint32_t temp = right;
        right = left ^ mixed;
        left = temp;
    }
    left ^= right;
    return merge(right, left);
}

int main() {
    // Read pairs
    FILE *fp = fopen("/app/pairs.txt", "r");
    if (!fp) { perror("pairs.txt"); return 1; }

