    char line[256];
    while (fgets(line, sizeof(line), fp) && num_pairs < 32) {
        unsigned long long p, c;
        if (sscanf(line, "%llu %llu", &p, &c) == 2) {
            pt[num_pairs] = p;
            ct[num_pairs] = c;
            num_pairs++;
        }
    }
    fclose(fp);
    printf("Read %d pairs\n", num_pairs);

    uint32_t exp[1<<20];
    for (int i = 0; i < (1<<20); i++) {
        exp[i] = expand(i);
