            return 0;
        }
        if (s % 100000 == 0) printf("  Progress: %d/%d\n", s, 1<<20);
    }

    // Test pattern: keys are expand(s+0), expand(s+0x55555), expand(s+0xAAAAA), expand(s+0xFFFFF)
    printf("\nTesting with fixed increments...\n");

    // Test if all 4 keys are the same
