    for (int s = 0; s < (1<<20); s++) {
        uint32_t keys[4] = {exp[s], exp[s], exp[s], exp[s]};
        int ok = 1;
        for (int i = 0; i < num_pairs && ok; i++) {
            if (encrypt(pt[i], keys) != ct[i]) ok = 0;
        }
        if (ok) {
            printf("FOUND all same! seed=0x%05X, key=0x%08X\n", s, exp[s]);
            return 0;
        }
        if (s % 100000 == 0) printf("  Progress: %d/%d\n", s, 1<<20);
    }

    // Test pattern: K0=K2, K1=K3 (this requires 2^40 search, too large)
    // Let's just test a limited range
    printf("\nTesting limited K0=K2, K1=K3...\n");
    for (int s0 = 0; s0 < 1000; s0++) {
        for (int s1 = 0; s1 < 1000; s1++) {
            uint32_t keys[4] = {exp[s0], exp[s1], exp[s0], exp[s1]};
